  ? 外侧放两次
  : 内侧，${if: ${b1短} ? 先斜后正 : 先正后斜 } 
}

${?l: 上北, 左西, 下南, 右东 [${!v:tmp_dir4} + 1]}${if: ${b同} 
  ? 斜方向，放两次
  : 正方向，${if: ${b1短} ? 先近后远 : 先远后近 } 
}

${if: ${b同} 
  ? ${?l: 上北, 左西, 下南, 右东 [${!v:tmp_dir4} + 1]}正点放两次
  : ${?l: 左上, 左下, 右下, 右上 [${!v:tmp_dir4} + 1]}，${if: ${b1短} ? 先角后编 : 先边后角 } 
}

